 32→void ULFPWorldMapEditorComponent::ToggleEditorMode()
 33→{
 34→	bEditorActive = !bEditorActive;
 35→
 36→	ALFPWorldMapManager* Manager = GetWorldMapManager();
 37→
 38→	if (bEditorActive)
 39→	{
 40→		// 编辑器开启：显示所有节点（临时揭开迷雾）
 41→		if (Manager)
 42→		{
 43→			for (const auto& Pair : Manager->GetNodeMap())
 44→			{
 45→				if (ALFPWorldMapNode* Node = Pair.Value)
 46→				{
 47→					Node->bIsRevealed = true;
 48→					Node->UpdateVisualState();
 49→				}
 50→			}
 51→
 52→			// 显示所有边
 53→			for (const auto& Pair : Manager->GetEdgeMap())
 54→			{
 55→				if (ALFPWorldMapEdge* Edge = Pair.Value)
 56→				{
 57→					Edge->SetActorHiddenInGame(false);
 58→				}
 59→			}
 60→		}
 61→	}
 62→	else
 63→	{
 64→		// 编辑器关闭：恢复迷雾状态
 65→		CurrentTool = ELFPWorldMapEditorTool::WMET_None;
 66→		SelectedNode = nullptr;
 67→		EdgeStartNode = nullptr;
 68→		EdgeRemovalStartNode = nullptr;
 69→
 70→		if (Manager)
 71→		{
 72→			Manager->UpdateFog();
 73→		}
 74→	}
 75→
 76→	OnEditorModeChanged.Broadcast(bEditorActive);
 77→	UE_LOG(LogTemp, Log, TEXT("世界地图编辑器: %s"), bEditorActive ? TEXT("开启") : TEXT("关闭"));
 78→}
