160→void ULFPWorldMapEditorComponent::HandleEdgeConnection(ALFPWorldMapNode* Node)
161→{
162→	if (!Node) return;
163→
164→	ALFPWorldMapManager* Manager = GetWorldMapManager();
165→	if (!Manager) return;
166→
167→	if (!EdgeStartNode)
168→	{
169→		// 第一次点击：记录起点
170→		EdgeStartNode = Node;
171→		EdgeStartNode->SetHighlighted(true);
172→		UE_LOG(LogTemp, Log, TEXT("选择边起点: 节点 %d"), EdgeStartNode->NodeID);
173→	}
174→	else
175→	{
176→		// 第二次点击：创建边
177→		if (EdgeStartNode != Node)
178→		{
179→			Manager->AddEdge(EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
180→			UE_LOG(LogTemp, Log, TEXT("创建边: %d -> %d (消耗 %d 回合)"),
181→				EdgeStartNode->NodeID, Node->NodeID, BrushEdgeTurnCost);
182→		}
183→
184→		// 清除高亮和状态
185→		EdgeStartNode->SetHighlighted(false);
186→		EdgeStartNode = nullptr;
187→	}
188→}
