190→void ULFPWorldMapEditorComponent::HandleEdgeRemoval(ALFPWorldMapNode* Node)
191→{
192→	if (!Node) return;
193→
194→	ALFPWorldMapManager* Manager = GetWorldMapManager();
195→	if (!Manager) return;
196→
197→	if (!EdgeRemovalStartNode)
198→	{
199→		// 第一次点击：记录起点
200→		EdgeRemovalStartNode = Node;
201→		EdgeRemovalStartNode->SetHighlighted(true);
202→		UE_LOG(LogTemp, Log, TEXT("选择要删除的边起点: 节点 %d"), EdgeRemovalStartNode->NodeID);
203→	}
204→	else
205→	{
206→		// 第二次点击：删除边
207→		if (EdgeRemovalStartNode != Node)
208→		{
209→			bool bRemoved = Manager->RemoveEdge(EdgeRemovalStartNode->NodeID, Node->NodeID);
210→			if (bRemoved)
211→			{
212→				UE_LOG(LogTemp, Log, TEXT("删除边: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
213→			}
214→			else
215→			{
216→				UE_LOG(LogTemp, Warning, TEXT("边不存在: %d <-> %d"), EdgeRemovalStartNode->NodeID, Node->NodeID);
217→			}
218→		}
219→
220→		// 清除高亮和状态
221→		EdgeRemovalStartNode->SetHighlighted(false);
222→		EdgeRemovalStartNode = nullptr;
223→	}
224→}
