226→void ULFPWorldMapEditorComponent::MoveSelectedNodeTo(FVector2D NewPos)
227→{
228→	if (!SelectedNode) return;
229→
230→	SelectedNode->SetPosition2D(NewPos);
231→
232→	// 更新所有关联边的视觉位置
233→	ALFPWorldMapManager* Manager = GetWorldMapManager();
234→	if (!Manager) return;
235→
236→	TArray<ALFPWorldMapNode*> Neighbors = Manager->GetNeighbors(SelectedNode->NodeID);
237→	for (ALFPWorldMapNode* Neighbor : Neighbors)
238→	{
239→		if (ALFPWorldMapEdge* Edge = Manager->GetEdge(SelectedNode->NodeID, Neighbor->NodeID))
240→		{
241→			Edge->UpdateVisualPosition(SelectedNode->GetActorLocation(), Neighbor->GetActorLocation());
242→		}
243→	}
244→
245→	UE_LOG(LogTemp, Log, TEXT("移动节点 %d 到 (%.1f, %.1f)"), SelectedNode->NodeID, NewPos.X, NewPos.Y);
246→}
