262→void ULFPWorldMapEditorComponent::EnterBattleMapEditor()
263→{
264→	if (!SelectedNode)
265→	{
266→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 未选中节点"));
267→		return;
268→	}
269→
270→	if (SelectedNode->NodeType != ELFPWorldNodeType::WNT_Battle)
271→	{
272→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 选中的不是战斗节点"));
273→		return;
274→	}
275→
276→	if (SelectedNode->BattleMapName.IsEmpty())
277→	{
278→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 战斗地图名称为空"));
279→		return;
280→	}
281→
282→	// 获取战斗地图编辑器组件（在同一个 PlayerController 上）
283→	ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
284→	if (!BattleEditor)
285→	{
286→		UE_LOG(LogTemp, Error, TEXT("EnterBattleMapEditor: 找不到战斗地图编辑器组件"));
287→		return;
288→	}
289→
290→	// 加载战斗地图
291→	bool bLoaded = BattleEditor->LoadMap(SelectedNode->BattleMapName);
292→	if (!bLoaded)
293→	{
294→		UE_LOG(LogTemp, Warning, TEXT("EnterBattleMapEditor: 加载战斗地图失败，创建新地图"));
295→		BattleEditor->NewMap(10, 10);
296→	}
297→
298→	// 激活战斗地图编辑器
299→	if (!BattleEditor->IsEditorActive())
300→	{
301→		BattleEditor->ToggleEditorMode();
302→	}
303→
304→	bIsEditingBattleMap = true;
305→	UE_LOG(LogTemp, Log, TEXT("进入战斗地图编辑: %s"), *SelectedNode->BattleMapName);
306→}
