308→void ULFPWorldMapEditorComponent::ReturnFromBattleMapEditor()
309→{
310→	if (!bIsEditingBattleMap) return;
311→
312→	ULFPMapEditorComponent* BattleEditor = GetOwner()->FindComponentByClass<ULFPMapEditorComponent>();
313→	if (BattleEditor && SelectedNode)
314→	{
315→		// 保存战斗地图（自动关联回节点）
316→		BattleEditor->SaveMap(SelectedNode->BattleMapName);
317→
318→		// 关闭战斗地图编辑器
319→		if (BattleEditor->IsEditorActive())
320→		{
321→			BattleEditor->ToggleEditorMode();
322→		}
323→	}
324→
325→	bIsEditingBattleMap = false;
326→	UE_LOG(LogTemp, Log, TEXT("返回世界地图编辑器"));
327→}
