218→void ULFPWorldMapEditorWidget::UpdateNodeInfo(ALFPWorldMapNode* Node)
219→{
220→	if (!SelectedNodeInfoText) return;
221→
222→	if (!Node)
223→	{
224→		SelectedNodeInfoText->SetText(FText::FromString(TEXT("未选中")));
225→		return;
226→	}
227→
228→	// 节点类型名
229→	FString TypeStr = UEnum::GetValueAsString(Node->NodeType);
230→	TypeStr = TypeStr.RightChop(TypeStr.Find(TEXT("::")) + 2);
231→
232→	FString Info = FString::Printf(TEXT("ID: %d | 类型: %s"), Node->NodeID, *TypeStr);
233→
234→	if (Node->NodeType == ELFPWorldNodeType::WNT_Battle)
235→	{
236→		Info += FString::Printf(TEXT(" | 星级: %d | 地图: %s"), Node->StarRating, *Node->BattleMapName);
237→	}
238→	else if (Node->NodeType == ELFPWorldNodeType::WNT_Event)
239→	{
240→		Info += FString::Printf(TEXT(" | 事件: %s"), *Node->EventID);
241→	}
242→
243→	SelectedNodeInfoText->SetText(FText::FromString(Info));
244→}
